/*
 * Hypervisor Resource Manager
 * Simulates resource allocation and management in a virtualized environment
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

// VM States
typedef enum {
    VM_CREATED,
    VM_CONFIGURED,
    VM_RUNNING,
    VM_PAUSED,
    VM_STOPPED,
    VM_TERMINATED
} VMState;

// VM Structure
typedef struct {
    int vm_id;
    char name[32];
    char os_type[32];
    int cpu_cores;
    int memory_mb;
    VMState state;
} VirtualMachine;

// Hypervisor Structure
typedef struct {
    int total_cpu;
    int total_memory;
    int available_cpu;
    int available_memory;
    VirtualMachine *vms[100];  // Max 100 VMs
    int vm_count;
} Hypervisor;

// Function prototypes
Hypervisor* create_hypervisor(int total_cpu, int total_memory);
VirtualMachine* create_vm(Hypervisor *hypervisor, char *name, char *os_type, int cpu, int memory);
bool configure_vm(Hypervisor *hypervisor, int vm_id);
bool start_vm(Hypervisor *hypervisor, int vm_id);
bool stop_vm(Hypervisor *hypervisor, int vm_id);
bool terminate_vm(Hypervisor *hypervisor, int vm_id);
void display_hypervisor_status(Hypervisor *hypervisor);
const char* get_state_string(VMState state);

int main() {
    // Create hypervisor with 16 CPU cores and 32GB RAM
    Hypervisor *hypervisor = create_hypervisor(16, 32768);

    printf("=== Virtual Machine Resource Manager Demo ===\n\n");

    // Create VMs
    VirtualMachine *vm1 = create_vm(hypervisor, "WebServer", "Ubuntu", 2, 4096);
    VirtualMachine *vm2 = create_vm(hypervisor, "Database", "CentOS", 4, 8192);
    VirtualMachine *vm3 = create_vm(hypervisor, "DevEnv", "Windows", 2, 4096);

    // Configure and start VMs
    printf("\n--- Starting VMs ---\n");
    configure_vm(hypervisor, 1);
    start_vm(hypervisor, 1);

    configure_vm(hypervisor, 2);
    start_vm(hypervisor, 2);

    configure_vm(hypervisor, 3);
    start_vm(hypervisor, 3);

    display_hypervisor_status(hypervisor);

    // Create and try to start 4th VM (may fail)
    printf("--- Creating 4th VM ---\n");
    VirtualMachine *vm4 = create_vm(hypervisor, "AppServer", "Ubuntu", 4, 8192);
    configure_vm(hypervisor, 4);
    start_vm(hypervisor, 4);  // Will likely fail due to insufficient resources

    display_hypervisor_status(hypervisor);

    // Stop a VM to free resources
    printf("--- Stopping VM 1 ---\n");
    stop_vm(hypervisor, 1);

    // Now try starting VM 4 again
    printf("--- Starting VM 4 after freeing resources ---\n");
    start_vm(hypervisor, 4);

    display_hypervisor_status(hypervisor);

    // Cleanup
    printf("\n--- Cleaning up ---\n");
    terminate_vm(hypervisor, 1);
    terminate_vm(hypervisor, 2);
    terminate_vm(hypervisor, 3);
    terminate_vm(hypervisor, 4);

    display_hypervisor_status(hypervisor);

    free(hypervisor);
    return 0;
}

// Create a new hypervisor
Hypervisor* create_hypervisor(int total_cpu, int total_memory) {
    Hypervisor *h = (Hypervisor*)malloc(sizeof(Hypervisor));
    h->total_cpu = total_cpu;
    h->total_memory = total_memory;
    h->available_cpu = total_cpu;
    h->available_memory = total_memory;
    h->vm_count = 0;
    return h;
}

// Create a new VM
VirtualMachine* create_vm(Hypervisor *hypervisor, char *name, char *os_type, int cpu, int memory) {
    if (hypervisor->vm_count >= 100) {
        printf("Error: Maximum VM limit reached\n");
        return NULL;
    }

    VirtualMachine *vm = (VirtualMachine*)malloc(sizeof(VirtualMachine));
    vm->vm_id = hypervisor->vm_count + 1;
    strncpy(vm->name, name, 31);
    strncpy(vm->os_type, os_type, 31);
    vm->cpu_cores = cpu;
    vm->memory_mb = memory;
    vm->state = VM_CREATED;

    hypervisor->vms[hypervisor->vm_count] = vm;
    hypervisor->vm_count++;

    printf("Created VM %d: %s [%s] CPU:%d RAM:%dMB\n", 
           vm->vm_id, vm->name, vm->os_type, vm->cpu_cores, vm->memory_mb);

    return vm;
}

// Configure a VM
bool configure_vm(Hypervisor *hypervisor, int vm_id) {
    if (vm_id < 1 || vm_id > hypervisor->vm_count) return false;

    VirtualMachine *vm = hypervisor->vms[vm_id - 1];
    if (vm->state != VM_CREATED) {
        printf("VM %d: Cannot configure - invalid state\n", vm_id);
        return false;
    }

    vm->state = VM_CONFIGURED;
    printf("VM %d (%s): Configured\n", vm_id, vm->name);
    return true;
}

// Start a VM (allocate resources)
bool start_vm(Hypervisor *hypervisor, int vm_id) {
    if (vm_id < 1 || vm_id > hypervisor->vm_count) return false;

    VirtualMachine *vm = hypervisor->vms[vm_id - 1];
    if (vm->state != VM_CONFIGURED && vm->state != VM_STOPPED) {
        printf("VM %d: Cannot start - invalid state\n", vm_id);
        return false;
    }

    // Check resource availability
    if (vm->cpu_cores > hypervisor->available_cpu || 
        vm->memory_mb > hypervisor->available_memory) {
        printf("VM %d (%s): Cannot start - insufficient resources!\n", 
               vm_id, vm->name);
        printf("  Required: CPU=%d, RAM=%dMB | Available: CPU=%d, RAM=%dMB\n",
               vm->cpu_cores, vm->memory_mb, 
               hypervisor->available_cpu, hypervisor->available_memory);
        return false;
    }

    // Allocate resources
    hypervisor->available_cpu -= vm->cpu_cores;
    hypervisor->available_memory -= vm->memory_mb;
    vm->state = VM_RUNNING;

    printf("VM %d (%s): Started | Resources: CPU=%d/%d, RAM=%d/%dMB\n", 
           vm_id, vm->name,
           hypervisor->available_cpu, hypervisor->total_cpu,
           hypervisor->available_memory, hypervisor->total_memory);

    return true;
}

// Stop a VM (release resources)
bool stop_vm(Hypervisor *hypervisor, int vm_id) {
    if (vm_id < 1 || vm_id > hypervisor->vm_count) return false;

    VirtualMachine *vm = hypervisor->vms[vm_id - 1];
    if (vm->state != VM_RUNNING) {
        printf("VM %d: Cannot stop - not running\n", vm_id);
        return false;
    }

    // Release resources
    hypervisor->available_cpu += vm->cpu_cores;
    hypervisor->available_memory += vm->memory_mb;
    vm->state = VM_STOPPED;

    printf("VM %d (%s): Stopped | Resources: CPU=%d/%d, RAM=%d/%dMB\n", 
           vm_id, vm->name,
           hypervisor->available_cpu, hypervisor->total_cpu,
           hypervisor->available_memory, hypervisor->total_memory);

    return true;
}

// Terminate a VM
bool terminate_vm(Hypervisor *hypervisor, int vm_id) {
    if (vm_id < 1 || vm_id > hypervisor->vm_count) return false;

    VirtualMachine *vm = hypervisor->vms[vm_id - 1];

    if (vm->state == VM_RUNNING) {
        // Release resources first
        hypervisor->available_cpu += vm->cpu_cores;
        hypervisor->available_memory += vm->memory_mb;
    }

    vm->state = VM_TERMINATED;
    printf("VM %d (%s): Terminated\n", vm_id, vm->name);

    free(vm);

    // Shift remaining VMs
    for (int i = vm_id - 1; i < hypervisor->vm_count - 1; i++) {
        hypervisor->vms[i] = hypervisor->vms[i + 1];
        if (hypervisor->vms[i]) {
            hypervisor->vms[i]->vm_id = i + 1;
        }
    }
    hypervisor->vm_count--;

    return true;
}

// Display hypervisor status
void display_hypervisor_status(Hypervisor *hypervisor) {
    printf("\n========== HYPERVISOR STATUS ==========\n");
    printf("Total Resources: CPU=%d cores, RAM=%dMB\n", 
           hypervisor->total_cpu, hypervisor->total_memory);
    printf("Available:       CPU=%d cores, RAM=%dMB\n", 
           hypervisor->available_cpu, hypervisor->available_memory);
    printf("Active VMs: %d\n", hypervisor->vm_count);
    printf("----------------------------------------\n");

    for (int i = 0; i < hypervisor->vm_count; i++) {
        VirtualMachine *vm = hypervisor->vms[i];
        printf("  VM %d: %-12s [%-10s] CPU:%d RAM:%dMB\n",
               vm->vm_id, vm->name, get_state_string(vm->state), 
               vm->cpu_cores, vm->memory_mb);
    }
    printf("========================================\n\n");
}

// Get state string
const char* get_state_string(VMState state) {
    switch (state) {
        case VM_CREATED:     return "Created";
        case VM_CONFIGURED:  return "Configured";
        case VM_RUNNING:     return "Running";
        case VM_PAUSED:      return "Paused";
        case VM_STOPPED:     return "Stopped";
        case VM_TERMINATED:  return "Terminated";
        default:             return "Unknown";
    }
}
